parameters.jsCode:
const order = $input.item.json.body;

const signals = [];
let riskScore = 0;

// Signal 1: Billing/shipping city mismatch
if (order.billing_city && order.shipping_city && order.billing_city !== order.shipping_city) {
  signals.push('Billing/shipping city mismatch');
  riskScore += 2;
}

// Signal 2: Billing/shipping country mismatch
if (order.billing_country && order.shipping_country && order.billing_country !== order.shipping_country) {
  signals.push('Billing/shipping country mismatch (international)');
  riskScore += 3;
}

// Signal 3: Suspicious email domain
const email = order.customer_email || '';
const suspiciousDomains = ['mailinator.com', 'guerrillamail.com', 'tempmail.com', 'throwam.com', 'yopmail.com'];
const emailDomain = email.split('@')[1] || '';
if (suspiciousDomains.includes(emailDomain)) {
  signals.push(`Suspicious email domain: ${emailDomain}`);
  riskScore += 5;
}

// Signal 4: Very high order value (>$2000)
const price = parseFloat(order.total_price) || 0;
if (price > 2000) {
  signals.push(`Unusually high order value: $${price}`);
  riskScore += 2;
}

// Determine risk level
let riskLevel;
if (riskScore >= 5) riskLevel = 'HIGH';
else if (riskScore >= 2) riskLevel = 'MEDIUM';
else riskLevel = 'LOW';

return {
  ...order,
  risk_signals: signals,
  risk_score: riskScore,
  risk_level: riskLevel,
  analyzed_at: new Date().toISOString()
};

