parameters.jsCode:
const aiText = $input.item.json.choices[0].message.content;
let assessment;
try {
  const m = aiText.match(/\{[\s\S]*\}/);
  assessment = m ? JSON.parse(m[0]) : {};
} catch(e) {
  assessment = { risk_level: 'MEDIUM', recommendation: 'manual_review', reasoning: 'AI parse error', action: 'Manual review required' };
}

return { ...$('Code — Calculate Risk Signals').item.json, ai_assessment: assessment };

